  failures: 0,
  threshold: 5,
  timeout: 60000, // 1 min
  state: 'CLOSED', // CLOSED, OPEN, HALF_OPEN

  async call(fn) {
    if (this.state === 'OPEN') {
      if (Date.now() - this.lastFailTime &gt; this.timeout) {
        this.state = 'HALF_OPEN';
      } else {
        throw new Error('Circuit breaker is OPEN');
      }
    }

    try {
      const result = await fn();
      if (this.state === 'HALF_OPEN') {
        this.state = 'CLOSED';
        this.failures = 0;
      }
      return result;
    } catch (error) {
      this.failures++;
      this.lastFailTime = Date.now();

      if (this.failures &gt;= this.threshold) {
        this.state = 'OPEN';
      }
      throw error;
    }
  }
};
